mapper.select:
SELECT COUNT(1)
FROM chat_session
WHERE created_at < #{end}

SELECT COUNT(1)
FROM chat_session
WHERE created_at >= #{start}
  AND created_at < #{end}

SELECT COUNT(1)
FROM chat_message
WHERE created_at >= #{start}
  AND created_at < #{end}
  AND role IN ('user', 'assistant')

SELECT duration_ms
FROM t_chat_turn_metric
WHERE created_at >= #{start}
  AND created_at < #{end}
  AND status = 'SUCCESS'
ORDER BY duration_ms ASC
